public class DEVLicenseModifiedTables extends RunBaseBatch implements BatchRetryable
{
    Days         calculateDays;

    DialogField  dlgCalculateDays;

    QueryRun       queryRun;

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        calculateDays
    #endmacro

}

Method.Source:
public Object dialog()
{
    DialogRunbase       dialog = super();
    ;
    dlgCalculateDays  = dialog.addFieldValue(extendedtypestr(Days), calculateDays, "Use last days", "Number of days to perform calculation");

    return dialog;
}

public boolean getFromDialog()
{
    ;
    calculateDays   = dlgCalculateDays.value();

    return super();
}

public Days parmCalculateDays(Days _calculateDays = calculateDays)
{
    calculateDays = _calculateDays;
    return calculateDays;
}

public void initQuery()
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds = query.addDataSource(tablenum(SqlDictionary));
    QueryBuildRange         qBR;
    ;
    qBR = SysQuery::findOrCreateRange(qbds, fieldnum(SqlDictionary, fieldId));
    qBR.status(RangeStatus::Locked);
    qBR.value('0');

    queryRun = new QueryRun(query);
}

public boolean unpack(container _packedClass)
{
    Version    version = RunBase::getVersion(_packedClass);
    container  queryCon;
    switch (version)
    {
        case #CurrentVersion:
            [version, #CurrentList, queryCon] = _packedClass;
            if (SysQuery::isPackedOk(queryCon))
            {
                queryRun = new QueryRun(queryCon);
            }
            else
            {
                this.initQuery();
            }
            break;
        default:
            return false;
    }
    return true;
}

public void run()
{
    int                     processedCounter;
    QueryBuildDataSource    qBDS;
    SqlDictionary    sqlDictionary;

    qBDS = queryRun.query().dataSourceTable(tableNum(SqlDictionary));

    while (queryRun.next())
    {
        sqlDictionary = queryRun.get(tablenum(SqlDictionary));
        this.processTable(sqlDictionary);
        processedCounter++;
    }
    info(strfmt(" %1 record(s) processed", processedCounter));
}

    public void processTable(SqlDictionary    _sqlDictionary)
    {
        DictTable		dictTable = new DictTable(_sqlDictionary.tabId);
        Common			commonRec;
        DEVLicenseTablesUsers  licenseTablesUsers, licenseTablesUsersUpd;

        delete_from licenseTablesUsers
            where licenseTablesUsers.TableName == _sqlDictionary.name;


        utcdatetime calcDate = DateTimeUtil::addDays(DateTimeUtil::utcNow(), -1 * calculateDays);

        if (dictTable.isView() || dictTable.isTempDb() || dictTable.isTempDb())
		{
			return;
        }
        if (dictTable.fieldName2Id("ModifiedDateTime") && dictTable.fieldName2Id("ModifiedBy"))
        {
            commonRec = dictTable.makeRecord();
            ttsbegin;
            while select crosscompany commonRec
                group by ModifiedBy
                where commonRec.ModifiedDateTime >= calcDate
            {
                licenseTablesUsers = null;
                licenseTablesUsers.TableName = _sqlDictionary.name;
                licenseTablesUsers.UserId = commonRec.ModifiedBy;
                licenseTablesUsers.Source = 'ModifiedBy';

                if (licenseTablesUsers.UserId)
                {
                    licenseTablesUsers.insert();
                }

            }
            ttscommit;
        }
        if (dictTable.fieldName2Id("CreatedDateTime") && dictTable.fieldName2Id("CreatedBy"))
        {
            commonRec = dictTable.makeRecord();
            ttsbegin;
            while select crosscompany commonRec
                group by CreatedBy
                where commonRec.CreatedDateTime >= calcDate
            {
                licenseTablesUsers = null;
                licenseTablesUsers.TableName = _sqlDictionary.name;
                licenseTablesUsers.UserId = commonRec.CreatedBy;
                licenseTablesUsers.Source = 'CreatedBy';

                if (licenseTablesUsers.UserId )
                {
                    licenseTablesUsers.insert();
                }

            }
            ttscommit;
        }
        ttsbegin;
        SysDataBaseLog    sysDatabaseLog;
        while select sysDatabaseLog
			group by Username
            where sysDatabaseLog.CreatedDateTime >= calcDate
                && sysDatabaseLog.table == dictTable.id()
        {
            licenseTablesUsers = null;
            licenseTablesUsers.TableName = _sqlDictionary.name;
            licenseTablesUsers.UserId = sysDatabaseLog.Username;
            licenseTablesUsers.Source = 'SysDataBaseLog';

            if (licenseTablesUsers.UserId )
            {
                licenseTablesUsers.insert();
            }
		}
        ttscommit;

    }

public static DEVLicenseModifiedTables construct()
{
    return new DEVLicenseModifiedTables();
}

static ClassDescription description()
{
    return "Calculate modified records";
}

public static void main(Args _args)
{
    DEVLicenseModifiedTables    runObject = DEVLicenseModifiedTables::construct();
    ;
    if (runObject.prompt())
    {
        runObject.runOperation();
    }
}
